class SAMLServiceProvider:
    def __init__(self, issuer_url, idp_url):
        self.issuer = issuer_url
        self.idp_url = idp_url
    
    def create_authn_request(self, destination_url, user_info):
        req = AuthnRequest()
        req.destination = destination_url
        req.issuer = entity.Issuer(text=self.issuer)
        nameid = samlp.saml20.elements.NameIDPolicy()
        nameid['Format'] = 'urn:oasis:names:tc:SAML:1.1:nameid-format:emailAddress'
